import React from "react";
import { motion } from "framer-motion";
import Button from "../common/Button";
import FloatingParticles from "../3d/FloatingParticles";
import { PORTFOLIO_DATA } from "@/utils/constants";

export default function Hero() {
  const containerVariants = {
    hidden: { opacity: 0 },
    visible: {
      opacity: 1,
      transition: {
        staggerChildren: 0.15,
        delayChildren: 0.2,
      },
    },
  };

  const itemVariants = {
    hidden: { opacity: 0, y: 20 },
    visible: {
      opacity: 1,
      y: 0,
      transition: { duration: 0.8, ease: "easeOut" },
    },
  };

  const scrollToContact = () => {
    const element = document.querySelector("#contact");
    if (element) element.scrollIntoView({ behavior: "smooth" });
  };

  return (
    <section className="relative min-h-screen flex items-center justify-center pt-16 overflow-hidden">
      {/* Background */}
      <div className="absolute inset-0 bg-gradient-to-b from-white via-blue-50/30 to-white dark:from-black dark:via-blue-950/10 dark:to-black -z-10" />
      
      {/* 3D Particles Background */}
      <div className="absolute inset-0 opacity-30 -z-10">
        <FloatingParticles />
      </div>

      <div className="max-w-6xl mx-auto px-4 sm:px-6 lg:px-8 w-full">
        <motion.div
          className="text-center"
          variants={containerVariants}
          initial="hidden"
          animate="visible"
        >
          {/* Greeting Badge */}
          <motion.div
            className="inline-flex items-center gap-2 px-4 py-2 rounded-full border border-blue-200 dark:border-blue-800 bg-blue-50/50 dark:bg-blue-900/20 mb-6"
            variants={itemVariants}
          >
            <div className="w-2 h-2 rounded-full bg-blue-600 animate-pulse" />
            <span className="text-sm font-medium text-blue-600 dark:text-blue-400">
              Welcome to my portfolio
            </span>
          </motion.div>

          {/* Main Heading */}
          <motion.h1
            className="text-5xl md:text-7xl font-bold tracking-tight text-zinc-900 dark:text-white mb-6 leading-tight"
            variants={itemVariants}
          >
            Hi, I'm{" "}
            <span className="bg-gradient-to-r from-blue-600 via-blue-500 to-blue-400 bg-clip-text text-transparent">
              {PORTFOLIO_DATA.personal.name.split(" ")[0]}
            </span>
          </motion.h1>

          {/* Role/Subtitle */}
          <motion.p
            className="text-xl md:text-2xl text-zinc-600 dark:text-zinc-400 mb-8 max-w-2xl mx-auto"
            variants={itemVariants}
          >
            {PORTFOLIO_DATA.personal.role}
          </motion.p>

          {/* Bio */}
          <motion.p
            className="text-lg text-zinc-600 dark:text-zinc-400 mb-10 max-w-xl mx-auto leading-relaxed"
            variants={itemVariants}
          >
            {PORTFOLIO_DATA.personal.bio}
          </motion.p>

          {/* CTA Buttons */}
          <motion.div
            className="flex flex-col sm:flex-row items-center justify-center gap-4"
            variants={itemVariants}
          >
            <Button
              variant="primary"
              size="lg"
              onClick={scrollToContact}
              className="w-full sm:w-auto"
            >
              Get In Touch
            </Button>
            <Button
              variant="outline"
              size="lg"
              className="w-full sm:w-auto"
              onClick={() => {
                const element = document.querySelector("#projects");
                if (element) element.scrollIntoView({ behavior: "smooth" });
              }}
            >
              View My Work
            </Button>
          </motion.div>

          {/* Scroll Indicator */}
          <motion.div
            className="mt-20 flex justify-center"
            animate={{ y: [0, 10, 0] }}
            transition={{ duration: 2, repeat: Infinity }}
          >
            <div className="w-8 h-12 border-2 border-zinc-300 dark:border-zinc-700 rounded-full flex items-start justify-center pt-2">
              <motion.div
                className="w-1 h-2 bg-blue-600 rounded-full"
                animate={{ opacity: [1, 0.3, 1] }}
                transition={{ duration: 2, repeat: Infinity }}
              />
            </div>
          </motion.div>
        </motion.div>
      </div>
    </section>
  );
}
